def get_db_connection():
    """Create a database connection using environment variables for credentials.
    
    Secrets are stored in environment variables (set via Secret Manager 
    integration in Cloud Functions, NOT hardcoded).
    """
    db_user = os.environ.get('DB_USER')
    db_pass = os.environ.get('DB_PASS')  # Injected from Secret Manager
    db_name = os.environ.get('DB_NAME')
    db_host = os.environ.get('DB_HOST')  # Cloud SQL private IP or Unix socket
    db_socket = os.environ.get('DB_SOCKET_PATH')  # e.g., /cloudsql/project:region:instance

    if not all([db_user, db_pass, db_name]):
        raise RuntimeError("Database configuration is incomplete")

    connect_kwargs = {
        'user': db_user,
        'password': db_pass,
        'database': db_name,
        'cursorclass': DictCursor,
        'charset': 'utf8mb4',
        'connect_timeout': 10,
        'read_timeout': 30,
        'autocommit': True,
    }

    # Prefer Unix socket for Cloud SQL (more secure, no network exposure)
    if db_socket:
        connect_kwargs['unix_socket'] = db_socket
    elif db_host:
        connect_kwargs['host'] = db_host
        connect_kwargs['port'] = int(os.environ.get('DB_PORT', 3306))
        # Enable SSL for TCP connections
        ssl_ca = os.environ.get('DB_SSL_CA')
        if ssl_ca:
            connect_kwargs['ssl'] = {'ca': ssl_ca}
    else:
        raise RuntimeError("No database host or socket path configured")

    return pymysql.connect(**connect_kwargs)


